sysauto_script.script:
// Scheduled Job: TRACENow Bulk Migration Runner
// Runs all Migration Jobs where status = 'new'

var jobQuery = new GlideRecord('u_tracenow_migration_job');
jobQuery.addQuery('u_status', 'new');
jobQuery.query();

while (jobQuery.next()) {
    var jobSysId  = jobQuery.getValue('sys_id');
    var tableName = jobQuery.getValue('u_table');

    gs.log('TRACENow Scheduled: Starting job ' + jobSysId, 'TRACENow');

    var connector   = new TRACENowSourceConnector(jobSysId);
    var fetchResult = connector.fetchRecords();

    if (!fetchResult.success) {
        jobQuery.u_status = 'error';
        jobQuery.u_error_detail = fetchResult.error;
        jobQuery.update();
        continue;
    }

    var builder     = new TRACENowExcelBuilder(jobSysId);
    var buildResult = builder.buildAndSave(fetchResult.records, fetchResult.fields, tableName);

    if (!buildResult.success) {
        jobQuery.u_status = 'error';
        jobQuery.u_error_detail = buildResult.error;
        jobQuery.update();
        continue;
    }

    var engine       = new TRACENowImportEngine(jobSysId);
    var importResult = engine.importFromAttachment(buildResult.attachSysId, tableName);

    jobQuery.u_status         = importResult.success ? 'complete' : 'error';
    jobQuery.u_total_imported = importResult.results ? importResult.results.success : 0;
    jobQuery.u_total_errors   = importResult.results ? importResult.results.error   : 0;
    jobQuery.update();
}
